class TestGenerateTransactionId:
    def test_returns_string(self):
        tx_id = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        assert isinstance(tx_id, str)

    def test_length_is_32(self):
        tx_id = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        assert len(tx_id) == 32

    def test_deterministic(self):
        id1 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        id2 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        assert id1 == id2

    def test_different_dates_differ(self):
        id1 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        id2 = generate_transaction_id(date(2025, 10, 6), "RAPPI", 45000.0, "bogota")
        assert id1 != id2

    def test_different_amounts_differ(self):
        id1 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        id2 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 50000.0, "bogota")
        assert id1 != id2

    def test_different_descriptions_differ(self):
        id1 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        id2 = generate_transaction_id(date(2025, 10, 5), "NETFLIX", 45000.0, "bogota")
        assert id1 != id2

    def test_different_banks_differ(self):
        id1 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        id2 = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "itau")
        assert id1 != id2

    def test_hex_characters_only(self):
        tx_id = generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota")
        assert all(c in "0123456789abcdef" for c in tx_id)


