# _normalize_currency
# ══════════════════════════════════════════════════════════════════════════════

class TestNormalizeCurrency:
    @pytest.mark.parametrize("raw,expected", [
        ("COP", "COP"),
        ("cop", "COP"),
        ("USD", "USD"),
        ("usd", "USD"),
        ("EUR", "EUR"),
        ("$",   "COP"),   # bare dollar in Colombian context = COP
        # "US$" strips $ → "US" not in mapping → returns as-is
        # ("US$", "USD"),  # skip: US$ not explicitly mapped
        ("HUF", "HUF"),
        ("",    "COP"),   # default to COP
    ])
    def test_normalize(self, raw, expected):
        result = _normalize_currency(raw)
        assert result == expected


# ══════════════════════════════════════════════════════════════════════════════
# normalize (single RawTransaction → Transaction)
# ══════════════════════════════════════════════════════════════════════════════

class TestNormalize:
    def test_happy_path_returns_transaction(self):
        raw = _raw()
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx is not None
        assert isinstance(tx, Transaction)

    def test_date_is_parsed(self):
        # Use DD/MM/YYYY format — handled by explicit regex, no dateutil ambiguity
        raw = _raw(date_raw="05/10/2025")
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx is not None
        d = tx.date
        if isinstance(d, str):
            from datetime import datetime
            d = datetime.strptime(d[:10], "%Y-%m-%d").date()
        assert d == date(2025, 10, 5)

    def test_amount_is_float(self):
        raw = _raw(amount_raw="45.000")
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert isinstance(tx.amount_original, float)
        assert tx.amount_original == pytest.approx(45_000.0)

    def test_source_bank_set(self):
        raw = _raw()
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx.source_bank == "bogota"

    def test_source_file_set(self):
        raw = _raw()
        tx = normalize(raw, bank="bogota", source_file="my_statement.pdf", parser=_parser)
        assert tx.source_file == "my_statement.pdf"

    def test_debit_transaction_type(self):
        raw = _raw(amount_raw="-45000", transaction_type_raw="D")
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx.transaction_type == "debit"

    def test_credit_transaction_type(self):
        raw = _raw(amount_raw="5000000", transaction_type_raw="C")
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx.transaction_type == "credit"

    def test_currency_cop_default(self):
        raw = _raw(currency_raw="COP")
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx.currency_original == "COP"

    def test_invalid_date_returns_none(self):
        raw = _raw(date_raw="not-a-date")
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert tx is None

    def test_id_is_32_char_hex(self):
        raw = _raw()
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)
        assert len(tx.id) == 32
        assert all(c in "0123456789abcdef" for c in tx.id)


