# normalize_batch
# ══════════════════════════════════════════════════════════════════════════════

class TestNormalizeBatch:
    def test_returns_tuple(self):
        raws = [_raw(), _raw(description="NETFLIX", amount_raw="37900")]
        result = normalize_batch(raws, "bogota", "test.pdf", _parser)
        assert isinstance(result, tuple)
        assert len(result) == 2

    def test_all_valid_returns_all(self):
        raws = [
            _raw(description="RAPPI",   amount_raw="45000"),
            _raw(description="NETFLIX", amount_raw="37900"),
            _raw(description="UBER",    amount_raw="15000"),
        ]
        txs, errors = normalize_batch(raws, "bogota", "test.pdf", _parser)
        assert len(txs) == 3

    def test_invalid_date_excluded(self):
        raws = [
            _raw(description="GOOD",  amount_raw="45000"),
            _raw(description="BAD",   amount_raw="37900", date_raw="INVALID"),
        ]
        txs, _ = normalize_batch(raws, "bogota", "test.pdf", _parser)
        assert len(txs) == 1

    def test_intra_batch_duplicates_get_suffix(self):
        # Same description + amount + date = same fingerprint → suffix applied
        raw = _raw()
        raws = [raw, _raw()]   # identical → same ID
        txs, _ = normalize_batch(raws, "bogota", "test.pdf", _parser)
        if len(txs) == 2:
            assert txs[0].id != txs[1].id  # suffix distinguishes them

    def test_errors_list_for_invalid(self):
        raws = [_raw(date_raw="INVALID")]
        txs, errors = normalize_batch(raws, "bogota", "test.pdf", _parser)
        # Either returns error or skips — either way, result is consistent
        assert isinstance(errors, list)

    def test_empty_input_returns_empty(self):
        txs, errors = normalize_batch([], "bogota", "test.pdf", _parser)
        assert txs == []


