class TestTransactionToDict:
    def _make_tx(self) -> Transaction:
        raw = _raw()
        return normalize(raw, bank="bogota", source_file="test.pdf", parser=_parser)

    def test_returns_dict(self):
        tx = self._make_tx()
        assert isinstance(transaction_to_dict(tx), dict)

    def test_contains_id(self):
        tx = self._make_tx()
        d = transaction_to_dict(tx)
        assert "id" in d

    def test_contains_date(self):
        tx = self._make_tx()
        d = transaction_to_dict(tx)
        assert "date" in d

    def test_contains_amount(self):
        tx = self._make_tx()
        d = transaction_to_dict(tx)
        assert "amount_original" in d or "amount_cop" in d

    def test_date_is_string_or_date(self):
        tx = self._make_tx()
        d = transaction_to_dict(tx)
        # date must be serializable (string or date object)
        assert isinstance(d["date"], (str, date))

    def test_all_values_are_serializable(self):
        import json
        tx = self._make_tx()
        d = transaction_to_dict(tx)
        # Convert dates to strings for JSON test
        safe = {k: str(v) if isinstance(v, date) else v for k, v in d.items()}
        json.dumps(safe)  # must not raise
